class Solution {
public:
    int subarraySum(vector<int>& nums, int k) {
        unordered_map<int,int> cnt{{0,1}};
        long long s = 0;
        int ans = 0;
        for (int x : nums) {
            s += x;
            if (cnt.count(s - k)) ans += cnt[s - k];
            cnt[s]++;
        }
        return ans;
    }
};
